const jobs = ($json.results || []);
const images = $input.first().json.images ||
"https://avatars.githubusercontent.com/u/218030750?s=96&v=4?auto=format&fit=crop&w=800&q=80";

const randomImage = images[Math.floor(Math.random() * images.length)];

let text = "🔥 CareerPulse AI — Jobs\n\n";
text += "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n";


let count = 1;
let driveCount = 0;

jobs.forEach((job) => {
  if (count > 5) return;

  let title = job.title || "Opportunity";

  if (title.toLowerCase().includes("software")) {
    title = "Software Developer";
  } else if (title.toLowerCase().includes("java")) {
    title = "Java Developer";
  } else if (title.toLowerCase().includes("data")) {
    title = "Data Analyst";
  } else if (title.toLowerCase().includes("frontend")) {
    title = "Frontend Developer";
  } else if (title.toLowerCase().includes("backend")) {
    title = "Backend Developer";
  } else if (title.toLowerCase().includes("ai")) {
    title = "AI Engineer";
  } else if (title.toLowerCase().includes("cyber")) {
    title = "Cybersecurity Role";
  }

  if (
    title.toLowerCase().includes("drive") ||
    title.toLowerCase().includes("test")
  ) {
    return;
  }

  text += `${count}️⃣ ${title}\n`;
  if (job.url.includes("linkedin")) {
      text += `🌐 Source: LinkedIn\n`;
    } else if (job.url.includes("indeed")) {
      text += `🌐 Source: Indeed\n`;
    } else if (job.url.includes("naukri")) {
      text += `🌐 Source: Naukri\n`;
    } else {
      text += `🌐 Source: Official Portal\n`;
    }
  text += `🔗Apply: ${job.url}\n\n`;
  text += "━━━━━━━━━━━━━━━━━━━━━━━━━\n\n";


  count++;
});

text += "🚀 Drives\n\n";
text += "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n";


jobs.forEach((job) => {
  const title = job.title || "";

  if (
    (title.toLowerCase().includes("drive") ||
      title.toLowerCase().includes("test")) &&
    driveCount < 2
  ) {
    text += `📌 ${title}\n`;
    text += `🔗Apply: ${job.url}\n\n`;
    text += "━━━━━━━━━━━━━━━━━━━━━━━━━\n\n";

    driveCount++;
  }
});

if (driveCount === 0) {
  text += "ℹ️ There are no drive or test updates in the next 30 days.\n\n";
}

text += "✅ Fresh Job Application links\n";
text += "CareerPulse-AI\n";


return [{
  json: {
    message: text,
    photo: randomImage
  }
}];
